diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..b9c925277aba 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1134,7 +1134,62 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,

   return nullptr;
 }
+// Fold (icmp ne X, C) \& (icmp ule (add X, -C), Y) -> icmp ult (add X, -C-1), Y
+// Fold (icmp eq X, C) | (icmp ugt (add X, -C), Y) -> icmp uge (add X, -C-1), Y
+static Value *foldNoWrapAddICmps(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                 bool IsAnd, InstCombiner::BuilderTy &Builder) {
+  // Match: icmp ne/eq X, C
+  ICmpInst::Predicate Pred0;
+  Value *X;
+  const APInt *C;
+  if (!match(Cmp0, m_ICmp(Pred0, m_Value(X), m_APIntAllowUndef(C))))
+    return nullptr;

+  bool IsNE = (Pred0 == ICmpInst::ICMP_NE);
+  bool IsEQ = (Pred0 == ICmpInst::ICMP_EQ);
+  if ((IsAnd && !IsNE) || (!IsAnd && !IsEQ))
+    return nullptr;
+
+  // Match: icmp ule/ugt (add X, -C), Y
+  ICmpInst::Predicate Pred1;
+  Value *Op0, *Op1;
+  if (!match(Cmp1, m_ICmp(Pred1, m_Value(Op0), m_Value(Op1))))
+    return nullptr;
+
+  const APInt *AddC;
+  Value *Y;
+  if (match(Op0, m_Add(m_Specific(X), m_APIntAllowUndef(AddC)))) {
+    Y = Op1;
+  } else if (match(Op1, m_Add(m_Specific(X), m_APIntAllowUndef(AddC)))) {
+    Y = Op0;
+    Pred1 = ICmpInst::getSwappedPredicate(Pred1);
+  } else {
+    return nullptr;
+  }
+
+  // Check that the add constant is the negation of the icmp constant.
+  if (*AddC != -*C)
+    return nullptr;
+
+  if (IsAnd && Pred1 == ICmpInst::ICMP_ULE) {
+    // (X + (-C)) <= Y  &&  X != C  ->  (X + (-C) - 1) < Y
+    APInt NewAddC = *AddC - 1;
+    if (NewAddC.isZero())
+      return Builder.CreateICmpULT(X, Y);
+    return Builder.CreateICmpULT(
+        Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewAddC)), Y);
+  }
+  if (!IsAnd && Pred1 == ICmpInst::ICMP_UGT) {
+    // (X + (-C)) > Y  ||  X == C  ->  (X + (-C) - 1) >= Y
+    APInt NewAddC = *AddC - 1;
+    if (NewAddC.isZero())
+      return Builder.CreateICmpUGE(X, Y);
+    return Builder.CreateICmpUGE(
+        Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewAddC)), Y);
+  }
+
+  return nullptr;
+}
 struct IntPart {
   Value *From;
   unsigned StartBit;
@@ -3107,6 +3162,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return X;
   }

+  // TODO: Verify whether this is safe for logical and/or.
+  if (!IsLogical) {
+    if (Value *X = foldNoWrapAddICmps(LHS, RHS, IsAnd, Builder))
+      return X;
+    if (Value *X = foldNoWrapAddICmps(RHS, LHS, IsAnd, Builder))
+      return X;
+  }
+
   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))
     return X;

